23→// FIXME: use something like "props: DUIProps<Foo, Bar>" during component
24→//  creation in order to avoid eliminate the use of "as SDUIComponentRenderer"
25→const adapters: Record<string, SDUIComponentRenderer> = {
26→  heading: HeadingAdapter as SDUIComponentRenderer,
27→  text: TextAdapter as SDUIComponentRenderer,
28→  balance_display: BalanceDisplayAdapter as SDUIComponentRenderer,
29→  points_input: PointsInputAdapter as SDUIComponentRenderer,
30→  button: ButtonAdapter as SDUIComponentRenderer,
31→  link: LinkAdapter as SDUIComponentRenderer,
32→  alert: AlertAdapter as SDUIComponentRenderer,
33→  list_text_icon: ListTextIconAdapter as SDUIComponentRenderer,
34→  separator: SeparatorAdapter as SDUIComponentRenderer,
35→  icon_text_row: IconTextRowAdapter as SDUIComponentRenderer,
36→  section_heading: SectionHeadingAdapter as SDUIComponentRenderer,
37→  rich_text: RichTextAdapter as SDUIComponentRenderer,
38→  voucher_card: VoucherCardAdapter as SDUIComponentRenderer,
39→  empty_state: EmptyStateAdapter as SDUIComponentRenderer,
40→  points_card: PointsCardAdapter as SDUIComponentRenderer,
41→  tab_bar: TabBarAdapter as SDUIComponentRenderer,
42→  transaction_item: TransactionItemAdapter as SDUIComponentRenderer,
43→  date_separator: DateSeparatorAdapter as SDUIComponentRenderer,
44→};
45→
46→export function registerAllAdapters(): void {
47→  Object.entries(adapters).forEach(([type, renderer]) => {
48→    registerToDefault(type, renderer);
49→  });
50→}
51→
52→export { adapters };
