 1→import React from 'react';
 2→import { Button } from '@semparar/design-system-app';
 3→import type {
 4→  SDUIComponentProps,
 5→  SDUIContext,
 6→  SDUIConditional,
 7→} from '../models';
 8→import { evaluateRule } from '../utils/jsonLogic';
 9→
10→interface ButtonProps extends SDUIComponentProps {
11→  text: string;
12→  disabled?: boolean;
13→  enabled?: SDUIConditional;
14→  mt?: string;
15→  mb?: string;
16→  icon?: string;
17→  isLoading?: boolean;
18→  testID?: string;
19→}
20→
21→export default function ButtonAdapter({
22→  props,
23→  context,
24→}: {
25→  props: ButtonProps;
26→  context: SDUIContext;
27→}) {
28→  const { text, disabled, enabled, mt, mb, icon, isLoading, testID } = props;
29→
30→  const isEnabled = enabled ? evaluateRule(enabled.rule, context) : true;
31→  const isDisabled = !!disabled || !isEnabled;
32→
33→  return (
34→    <Button
35→      text={String(text)}
36→      onPress={() => {}}
37→      disabled={isDisabled}
38→      mt={mt}
39→      mb={mb}
40→      icon={icon}
41→      isLoading={!!isLoading}
42→      testID={testID}
43→    />
44→  );
45→}
